 41→function skipWhitespace(doc: string, pos: number): number {
 42→  while (pos < doc.length && /\s/.test(doc[pos])) pos++;
 43→  return pos;
 44→}
 45→
 46→function skipValue(doc: string, pos: number): number {
 47→  pos = skipWhitespace(doc, pos);
 48→  if (pos >= doc.length) return pos;
 49→
 50→  const ch = doc[pos];
 51→  if (ch === '{' || ch === '[') {
 52→    const open = ch;
 53→    const close = open === '{' ? '}' : ']';
 54→    let depth = 1;
 55→    pos++;
 56→    let inString = false;
 57→    let escaped = false;
 58→    while (pos < doc.length && depth > 0) {
 59→      const c = doc[pos];
 60→      if (inString) {
 61→        if (escaped) { escaped = false; }
 62→        else if (c === '\\') { escaped = true; }
 63→        else if (c === '"') { inString = false; }
 64→      } else {
 65→        if (c === '"') inString = true;
 66→        else if (c === open) depth++;
 67→        else if (c === close) depth--;
 68→      }
 69→      pos++;
 70→    }
 71→    return pos;
 72→  }
 73→
 74→  if (ch === '"') {
 75→    pos++;
 76→    while (pos < doc.length) {
 77→      if (doc[pos] === '\\') { pos += 2; continue; }
 78→      if (doc[pos] === '"') { pos++; break; }
 79→      pos++;
 80→    }
 81→    return pos;
 82→  }
 83→
 84→  while (pos < doc.length && /[^\s,\]}]/.test(doc[pos])) pos++;
 85→  return pos;
 86→}
