 88→function findJsonPath(doc: string, path: string): { from: number; to: number } | null {
 89→  const segments = path.split('/').filter(Boolean);
 90→  let pos = 0;
 91→
 92→  for (const seg of segments) {
 93→    const isIndex = /^\d+$/.test(seg);
 94→
 95→    if (isIndex) {
 96→      const idx = parseInt(seg, 10);
 97→      const arrStart = doc.indexOf('[', pos);
 98→      if (arrStart === -1) return null;
 99→      pos = arrStart + 1;
100→
101→      for (let i = 0; i < idx; i++) {
102→        pos = skipWhitespace(doc, pos);
103→        if (pos >= doc.length || doc[pos] === ']') return null;
104→        pos = skipValue(doc, pos);
105→        pos = skipWhitespace(doc, pos);
106→        if (pos < doc.length && doc[pos] === ',') pos++;
107→      }
108→
109→      pos = skipWhitespace(doc, pos);
110→      if (pos >= doc.length || doc[pos] === ']') return null;
111→    } else {
112→      const escaped = seg.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
113→      const keyPattern = new RegExp(`(?:"${escaped}"|${escaped})\\s*:`);
114→      const match = keyPattern.exec(doc.slice(pos));
115→      if (!match) return null;
116→      pos += match.index;
117→    }
118→  }
119→
120→  let lineEnd = doc.indexOf('\n', pos);
121→  if (lineEnd === -1) lineEnd = doc.length;
122→
123→  return { from: pos, to: Math.min(pos + 40, lineEnd) };
124→}
