126→function humanizeMessage(error: Ajv.ErrorObject): string {
127→  const { keyword, params, instancePath, message } = error;
128→
129→  if (keyword === 'enum' && instancePath.endsWith('/type')) {
130→    const value = (error as any).data;
131→    if (typeof value === 'string') {
132→      const suggestion = didYouMean(value, [...knownTypes]);
133→      const base = `Unknown component type "${value}"`;
134→      return suggestion ? `${base} — did you mean "${suggestion}"?` : `${base}. Valid types: ${knownTypes.join(', ')}`;
135→    }
136→  }
137→
138→  if (keyword === 'required') {
139→    const missing = (params as any).missingProperty;
140→    return `Missing required property "${missing}"`;
141→  }
142→
143→  if (keyword === 'additionalProperties') {
144→    const extra = (params as any).additionalProperty;
145→    return `Unknown property "${extra}"`;
146→  }
147→
148→  if (keyword === 'type') {
149→    const expected = (params as any).type;
150→    return `Expected ${expected}${message ? ` — ${message}` : ''}`;
151→  }
152→
153→  if (keyword === 'const') {
154→    return `Expected value: ${JSON.stringify((params as any).allowedValue)}`;
155→  }
156→
157→  return message || 'Schema validation error';
158→}
