160→function validateComponentProps(parsed: any, doc: string): Diagnostic[] {
161→  const diagnostics: Diagnostic[] = [];
162→
163→  const components: Array<{ component: any; path: string }> = [];
164→
165→  if (parsed.header) components.push({ component: parsed.header, path: '/header' });
166→  if (parsed.footer) components.push({ component: parsed.footer, path: '/footer' });
167→  if (Array.isArray(parsed.body)) {
168→    parsed.body.forEach((c: any, i: number) => components.push({ component: c, path: `/body/${i}` }));
169→  }
170→
171→  for (const { component, path } of components) {
172→    const type = component?.type;
173→    if (!type || typeof type !== 'string') continue;
174→
175→    if (!knownTypes.includes(type as any)) {
176→      const suggestion = didYouMean(type, [...knownTypes]);
177→      const loc = findJsonPath(doc, `${path}/type`);
178→      const msg = suggestion
179→        ? `Unknown component type "${type}" — did you mean "${suggestion}"?`
180→        : `Unknown component type "${type}". Valid: ${knownTypes.join(', ')}`;
181→      diagnostics.push({
182→        from: loc?.from ?? 0,
183→        to: loc?.to ?? 0,
184→        severity: 'warning',
185→        message: msg,
186→        source: 'sdui-schema',
187→      });
188→      continue;
189→    }
190→
191→    const propsSchema = componentPropsSchemas[type] as any;
192→    if (!propsSchema) continue;
193→
194→    const required: string[] = propsSchema.required || [];
195→    const props = component.props || {};
196→    const knownProps = Object.keys(propsSchema.properties || {});
197→
198→    for (const req of required) {
199→      if (props[req] === undefined || props[req] === null) {
200→        const loc = findJsonPath(doc, `${path}/props`);
201→        diagnostics.push({
202→          from: loc?.from ?? 0,
203→          to: loc?.to ?? 0,
204→          severity: 'error',
205→          message: `"${type}" requires property "${req}"`,
206→          source: 'sdui-schema',
207→        });
208→      }
209→    }
210→
211→    for (const propName of Object.keys(props)) {
212→      if (!knownProps.includes(propName)) {
213→        const suggestion = didYouMean(propName, knownProps);
214→        const loc = findJsonPath(doc, `${path}/props/${propName}`);
215→        const msg = suggestion
216→          ? `Unknown prop "${propName}" on "${type}" — did you mean "${suggestion}"?`
217→          : `Unknown prop "${propName}" on "${type}". Valid: ${knownProps.join(', ')}`;
218→        diagnostics.push({
219→          from: loc?.from ?? 0,
220→          to: loc?.to ?? 0,
221→          severity: 'warning',
222→          message: msg,
223→          source: 'sdui-schema',
224→        });
225→      }
226→    }
227→  }
228→
229→  return diagnostics;
230→}
