232→export function validateSduiJson(doc: string): Diagnostic[] {
233→  let parsed: any;
234→
235→  try {
236→    parsed = JSON.parse(doc);
237→  } catch {
238→    try {
239→      parsed = JSON5.parse(doc);
240→    } catch {
241→      return [];
242→    }
243→  }
244→
245→  if (typeof parsed !== 'object' || parsed === null || Array.isArray(parsed)) {
246→    return [{
247→      from: 0,
248→      to: Math.min(doc.length, 1),
249→      severity: 'error',
250→      message: 'SDUI screen must be a JSON object',
251→      source: 'sdui-schema',
252→    }];
253→  }
254→
255→  const diagnostics: Diagnostic[] = [];
256→
257→  validate(parsed);
258→  if (validate.errors) {
259→    for (const error of validate.errors) {
260→      if (error.keyword === 'if') continue;
261→
262→      const jsonPath = error.instancePath || '';
263→      const loc = findJsonPath(doc, jsonPath);
264→      const msg = humanizeMessage(error);
265→
266→      diagnostics.push({
267→        from: loc?.from ?? 0,
268→        to: loc?.to ?? 0,
269→        severity: error.keyword === 'required' || error.keyword === 'type' ? 'error' : 'warning',
270→        message: msg,
271→        source: 'sdui-schema',
272→      });
273→    }
274→  }
275→
276→  diagnostics.push(...validateComponentProps(parsed, doc));
277→
278→  const seen = new Set<string>();
279→  return diagnostics.filter(d => {
280→    const key = `${d.from}:${d.severity}:${d.message}`;
281→    if (seen.has(key)) return false;
282→    seen.add(key);
283→    return true;
284→  });
285→}
